// Formater la réponse de mise à jour
const response = $input.item.json.result || $input.item.json;
const data = response.data || response;

if (response.status !== 'success') {
  return {
    json: {
      success: false,
      message: `❌ Erreur lors de la mise à jour du service: ${response.msg || 'Erreur inconnue'}`,
      error: response.msg
    }
  };
}

// Le nom du service peut être dans response.service, data.id, ou la clé d'objet dans data
const serviceName = response.service || data.id || (typeof data === 'object' && Object.keys(data)[0]) || 'inconnu';
let formattedText = `✅ Service **${serviceName}** mis à jour avec succès.\n\n`;

if (data.last_update) {
  const date = new Date(data.last_update).toLocaleString('fr-FR');
  formattedText += `• Mis à jour le: ${date}\n`;
}

formattedText += '\n⚠️ N\'oubliez pas de recharger la configuration avec `reload_config` pour appliquer les changements.';

return {
  json: {
    success: true,
    message: formattedText,
    service: data
  }
};
